import type { MouseEvent } from 'react'
import type { Coordinate, SensorConfig, TargetConfig } from '../types/simulation'

type TargetCanvasProps = {
  target: TargetConfig
  sensors: SensorConfig[]
  actualImpact: Coordinate
  estimatedImpact: Coordinate | null
  onImpactSelect: (impact: Coordinate) => void
}

const VIEWBOX_SIZE = 240
const MARGIN = 18

export function TargetCanvas({
  target,
  sensors,
  actualImpact,
  estimatedImpact,
  onImpactSelect,
}: TargetCanvasProps) {
  const scaleX = (VIEWBOX_SIZE - MARGIN * 2) / target.width
  const scaleY = (VIEWBOX_SIZE - MARGIN * 2) / target.height
  const scale = Math.min(scaleX, scaleY)
  const viewWidth = target.width * scale
  const viewHeight = target.height * scale
  const left = (VIEWBOX_SIZE - viewWidth) / 2
  const top = (VIEWBOX_SIZE - viewHeight) / 2

  function toSvgPoint(point: Coordinate) {
    return {
      x: left + (point.x + target.width / 2) * scale,
      y: top + (target.height / 2 - point.y) * scale,
    }
  }

  function handleClick(event: MouseEvent<SVGSVGElement>) {
    const bounds = event.currentTarget.getBoundingClientRect()
    const svgX = ((event.clientX - bounds.left) / bounds.width) * VIEWBOX_SIZE
    const svgY = ((event.clientY - bounds.top) / bounds.height) * VIEWBOX_SIZE

    if (
      svgX < left ||
      svgX > left + viewWidth ||
      svgY < top ||
      svgY > top + viewHeight
    ) {
      return
    }

    const x = (svgX - left) / scale - target.width / 2
    const y = target.height / 2 - (svgY - top) / scale
    onImpactSelect({ x, y })
  }

  const actualPoint = toSvgPoint(actualImpact)
  const estimatedPoint = estimatedImpact ? toSvgPoint(estimatedImpact) : null

  return (
    <div className="target-card">
      <div className="panel-heading">
        <div>
          <p className="eyebrow">Target View</p>
          <h2>{target.label}</h2>
        </div>
        <p className="panel-copy">Click anywhere on the plate to generate the true impact location.</p>
      </div>
      <svg
        className="target-svg"
        viewBox={`0 0 ${VIEWBOX_SIZE} ${VIEWBOX_SIZE}`}
        onClick={handleClick}
        role="img"
        aria-label="Interactive target surface"
      >
        <defs>
          <pattern id="target-grid" width="24" height="24" patternUnits="userSpaceOnUse">
            <path d="M 24 0 L 0 0 0 24" fill="none" stroke="rgba(108, 83, 58, 0.16)" strokeWidth="1" />
          </pattern>
        </defs>
        <rect x="0" y="0" width={VIEWBOX_SIZE} height={VIEWBOX_SIZE} rx="24" className="target-frame" />
        <rect
          x={left}
          y={top}
          width={viewWidth}
          height={viewHeight}
          rx="20"
          className="target-plate"
        />
        <rect
          x={left}
          y={top}
          width={viewWidth}
          height={viewHeight}
          rx="20"
          fill="url(#target-grid)"
          pointerEvents="none"
        />
        <line x1={left} x2={left + viewWidth} y1={VIEWBOX_SIZE / 2} y2={VIEWBOX_SIZE / 2} className="target-axis" />
        <line y1={top} y2={top + viewHeight} x1={VIEWBOX_SIZE / 2} x2={VIEWBOX_SIZE / 2} className="target-axis" />
        {sensors.filter((sensor) => sensor.enabled).map((sensor) => {
          const sensorPoint = toSvgPoint({ x: sensor.x, y: sensor.y })
          return (
            <g key={sensor.id}>
              <circle cx={sensorPoint.x} cy={sensorPoint.y} r="7" className="sensor-node" />
              <text x={sensorPoint.x + 10} y={sensorPoint.y - 10} className="sensor-label">
                {sensor.label}
              </text>
            </g>
          )
        })}
        <circle cx={actualPoint.x} cy={actualPoint.y} r="6" className="impact-actual" />
        {estimatedPoint ? (
          <>
            <circle cx={estimatedPoint.x} cy={estimatedPoint.y} r="9" className="impact-estimated-ring" />
            <circle cx={estimatedPoint.x} cy={estimatedPoint.y} r="5" className="impact-estimated" />
            <line
              x1={actualPoint.x}
              y1={actualPoint.y}
              x2={estimatedPoint.x}
              y2={estimatedPoint.y}
              className="impact-connection"
            />
          </>
        ) : null}
      </svg>
      <div className="legend-row">
        <span><i className="legend-swatch actual"></i> True impact</span>
        <span><i className="legend-swatch estimated"></i> Estimated impact</span>
        <span><i className="legend-swatch sensor"></i> Active sensor</span>
      </div>
    </div>
  )
}

import { clampImpact, computeDistance } from '../geometry'
import type {
  Coordinate,
  SensorConfig,
  SensorMeasurement,
  SolverResult,
  TargetConfig,
  TraceEntry,
} from '../../types/simulation'

type SolverInput = {
  target: TargetConfig
  sensors: SensorConfig[]
  measurements: SensorMeasurement[]
  speedOfSound: number
}

const MAX_ITERATIONS = 16
const EPSILON = 1e-6

export function solveTdoa(input: SolverInput): SolverResult {
  const activeSensors = input.sensors.filter((sensor) => sensor.enabled)

  if (activeSensors.length < 3 || input.measurements.length < 3) {
    return buildFailure('Need at least 3 active sensors to solve.', 0)
  }

  const measurementsById = new Map(
    input.measurements.map((measurement) => [measurement.sensorId, measurement]),
  )
  const referenceMeasurement = [...input.measurements].sort(
    (left, right) => left.noisyTimeSeconds - right.noisyTimeSeconds,
  )[0]
  const referenceSensor = activeSensors.find(
    (sensor) => sensor.id === referenceMeasurement.sensorId,
  )

  if (!referenceSensor) {
    return buildFailure('Reference sensor missing from configuration.', 0)
  }

  const trace: TraceEntry[] = [
    {
      label: 'Reference sensor',
      value: `${referenceSensor.label} (${referenceMeasurement.noisyTimeSeconds.toFixed(6)} s)`,
    },
  ]

  let estimate = clampImpact(getInitialGuess(activeSensors, input.measurements), input.target)
  let converged = false
  let iterations = 0

  for (let iteration = 0; iteration < MAX_ITERATIONS; iteration += 1) {
    iterations = iteration + 1

    const refDistance = computeDistance(estimate, referenceSensor)
    const refTime = referenceMeasurement.noisyTimeSeconds
    const jacobianRows: Array<{ dx: number; dy: number; residual: number }> = []

    for (const sensor of activeSensors) {
      if (sensor.id === referenceSensor.id) {
        continue
      }

      const measurement = measurementsById.get(sensor.id)
      if (!measurement) {
        continue
      }

      const sensorDistance = computeDistance(estimate, sensor)
      const predictedDelta = (sensorDistance - refDistance) / input.speedOfSound
      const measuredDelta = measurement.noisyTimeSeconds - refTime
      const residual = predictedDelta - measuredDelta
      const dx =
        (estimate.x - sensor.x) / (input.speedOfSound * Math.max(sensorDistance, EPSILON)) -
        (estimate.x - referenceSensor.x) /
          (input.speedOfSound * Math.max(refDistance, EPSILON))
      const dy =
        (estimate.y - sensor.y) / (input.speedOfSound * Math.max(sensorDistance, EPSILON)) -
        (estimate.y - referenceSensor.y) /
          (input.speedOfSound * Math.max(refDistance, EPSILON))

      jacobianRows.push({ dx, dy, residual })
    }

    if (jacobianRows.length < 2) {
      return buildFailure('Insufficient TDOA pairs for solving.', iterations)
    }

    let a11 = 0
    let a12 = 0
    let a22 = 0
    let b1 = 0
    let b2 = 0

    for (const row of jacobianRows) {
      a11 += row.dx * row.dx
      a12 += row.dx * row.dy
      a22 += row.dy * row.dy
      b1 += row.dx * row.residual
      b2 += row.dy * row.residual
    }

    const determinant = a11 * a22 - a12 * a12
    if (Math.abs(determinant) < EPSILON) {
      trace.push({
        label: `Iteration ${iterations}`,
        value: 'Degenerate geometry prevented a stable solve.',
      })
      break
    }

    const stepX = (-a22 * b1 + a12 * b2) / determinant
    const stepY = (a12 * b1 - a11 * b2) / determinant

    estimate = clampImpact(
      {
        x: estimate.x + stepX,
        y: estimate.y + stepY,
      },
      input.target,
    )

    trace.push({
      label: `Iteration ${iterations}`,
      value: `dx ${stepX.toFixed(3)} ${input.target.units}, dy ${stepY.toFixed(3)} ${input.target.units}`,
    })

    if (Math.sqrt(stepX * stepX + stepY * stepY) < 0.001) {
      converged = true
      break
    }
  }

  const residualMicros = computeResidualMicros(
    estimate,
    activeSensors,
    input.measurements,
    referenceSensor,
    referenceMeasurement,
    input.speedOfSound,
  )
  if (Number.isFinite(residualMicros) && residualMicros <= 0.5) {
    converged = true
  }

  trace.push({
    label: 'Estimated impact',
    value: `${estimate.x.toFixed(2)}, ${estimate.y.toFixed(2)} ${input.target.units}`,
  })
  trace.push({
    label: 'Residual',
    value: `${residualMicros.toFixed(2)} microseconds RMS`,
  })

  return {
    estimatedImpact: estimate,
    converged,
    iterations,
    residualMicros,
    confidence: getConfidence(residualMicros, converged),
    trace,
  }
}

function computeResidualMicros(
  estimate: Coordinate,
  activeSensors: SensorConfig[],
  measurements: SensorMeasurement[],
  referenceSensor: SensorConfig,
  referenceMeasurement: SensorMeasurement,
  speedOfSound: number,
): number {
  const measurementMap = new Map(
    measurements.map((measurement) => [measurement.sensorId, measurement]),
  )
  const refDistance = computeDistance(estimate, referenceSensor)
  const refTime = referenceMeasurement.noisyTimeSeconds
  let sum = 0
  let count = 0

  for (const sensor of activeSensors) {
    if (sensor.id === referenceSensor.id) {
      continue
    }

    const measurement = measurementMap.get(sensor.id)
    if (!measurement) {
      continue
    }

    const distance = computeDistance(estimate, sensor)
    const predictedDelta = (distance - refDistance) / speedOfSound
    const measuredDelta = measurement.noisyTimeSeconds - refTime
    const residual = (predictedDelta - measuredDelta) * 1_000_000
    sum += residual * residual
    count += 1
  }

  return count > 0 ? Math.sqrt(sum / count) : Number.NaN
}

function getInitialGuess(
  sensors: SensorConfig[],
  measurements: SensorMeasurement[],
): Coordinate {
  const measurementMap = new Map(
    measurements.map((measurement) => [measurement.sensorId, measurement]),
  )

  let totalWeight = 0
  let x = 0
  let y = 0

  for (const sensor of sensors) {
    const measurement = measurementMap.get(sensor.id)
    if (!measurement) {
      continue
    }

    const weight = 1 / Math.max(measurement.noisyTimeSeconds, EPSILON)
    totalWeight += weight
    x += sensor.x * weight
    y += sensor.y * weight
  }

  if (totalWeight === 0) {
    return { x: 0, y: 0 }
  }

  return {
    x: x / totalWeight,
    y: y / totalWeight,
  }
}

function getConfidence(residualMicros: number, converged: boolean) {
  if (!converged || Number.isNaN(residualMicros)) {
    return 'low' as const
  }

  if (residualMicros <= 10) {
    return 'high' as const
  }

  if (residualMicros <= 40) {
    return 'medium' as const
  }

  return 'low' as const
}

function buildFailure(message: string, iterations: number): SolverResult {
  return {
    estimatedImpact: null,
    converged: false,
    iterations,
    residualMicros: Number.NaN,
    confidence: 'low',
    trace: [{ label: 'Solver', value: message }],
  }
}

