  return {
    estimatedImpact: estimate,
    converged,
    iterations,
    residualMicros,
    confidence: getConfidence(residualMicros, converged),
    trace,
  }
}

function computeResidualMicros(
  estimate: Coordinate,
  activeSensors: SensorConfig[],
  measurements: SensorMeasurement[],
  referenceSensor: SensorConfig,
  referenceMeasurement: SensorMeasurement,
  speedOfSound: number,
): number {
  const measurementMap = new Map(
    measurements.map((measurement) => [measurement.sensorId, measurement]),
  )
  const refDistance = computeDistance(estimate, referenceSensor)
  const refTime = referenceMeasurement.noisyTimeSeconds
  let sum = 0
  let count = 0

  for (const sensor of activeSensors) {
    if (sensor.id === referenceSensor.id) {
      continue
    }

    const measurement = measurementMap.get(sensor.id)
    if (!measurement) {
      continue
    }

    const distance = computeDistance(estimate, sensor)
    const predictedDelta = (distance - refDistance) / speedOfSound
    const measuredDelta = measurement.noisyTimeSeconds - refTime
    const residual = (predictedDelta - measuredDelta) * 1_000_000
    sum += residual * residual
    count += 1
  }

  return count > 0 ? Math.sqrt(sum / count) : Number.NaN
}

function getInitialGuess(
  sensors: SensorConfig[],
  measurements: SensorMeasurement[],
): Coordinate {
  const measurementMap = new Map(
    measurements.map((measurement) => [measurement.sensorId, measurement]),
  )

  let totalWeight = 0
  let x = 0
  let y = 0

  for (const sensor of sensors) {
    const measurement = measurementMap.get(sensor.id)
    if (!measurement) {
      continue
    }

    const weight = 1 / Math.max(measurement.noisyTimeSeconds, EPSILON)
    totalWeight += weight
    x += sensor.x * weight
    y += sensor.y * weight
  }

  if (totalWeight === 0) {
    return { x: 0, y: 0 }
  }

  return {
    x: x / totalWeight,
    y: y / totalWeight,
  }
}

function getConfidence(residualMicros: number, converged: boolean) {
  if (!converged || Number.isNaN(residualMicros)) {
    return 'low' as const
  }

  if (residualMicros <= 10) {
    return 'high' as const
  }

  if (residualMicros <= 40) {
    return 'medium' as const
  }

  return 'low' as const
}

function buildFailure(message: string, iterations: number): SolverResult {
  return {
    estimatedImpact: null,
    converged: false,
    iterations,
    residualMicros: Number.NaN,
    confidence: 'low',
    trace: [{ label: 'Solver', value: message }],
  }
}
"}

