{"filePath":"/Users/pisan/bitbucket/pisanuw/bullet/src/lib/storage.ts","content":"import type { SimulationState } from '../types/simulation'

const STORAGE_KEY = 'bullet-simulator-state'

export function loadStoredState(): SimulationState | null {
  if (!hasStorage()) {
    return null
  }

  const rawValue = window.localStorage.getItem(STORAGE_KEY)
  if (!rawValue) {
    return null
  }

  try {
    return JSON.parse(rawValue) as SimulationState
  } catch {
    return null
  }
}

export function saveStoredState(state: SimulationState): void {
  if (!hasStorage()) {
    return
  }

  window.localStorage.setItem(STORAGE_KEY, JSON.stringify(state))
}

function hasStorage(): boolean {
  return typeof window !== 'undefined' && 'localStorage' in window
}
"}

{"filePath":"/Users/pisan/bitbucket/pisanuw/bullet/src/components/TargetCanvas.tsx","content":"import type { Coordinate, SensorConfig, TargetConfig } from '../types/simulation'

type TargetCanvasProps = {
  target: TargetConfig
  sensors: SensorConfig[]
  actualImpact: Coordinate
  estimatedImpact: Coordinate | null
  onImpactSelect: (impact: Coordinate) => void
}

const VIEWBOX_SIZE = 240
const MARGIN = 18

export function TargetCanvas({
  target,
  sensors,
  actualImpact,
  estimatedImpact,
  onImpactSelect,
}: TargetCanvasProps) {
  const scaleX = (VIEWBOX_SIZE - MARGIN * 2) / target.width
  const scaleY = (VIEWBOX_SIZE - MARGIN * 2) / target.height
  const scale = Math.min(scaleX, scaleY)
  const viewWidth = target.width * scale
  const viewHeight = target.height * scale
  const left = (VIEWBOX_SIZE - viewWidth) / 2
  const top = (VIEWBOX_SIZE - viewHeight) / 2

  function toSvgPoint(point: Coordinate) {
    return {
      x: left + (point.x + target.width / 2) * scale,
      y: top + (target.height / 2 - point.y) * scale,
    }
  }

  function handleClick(event: React.MouseEvent<SVGSVGElement>) {
    const bounds = event.currentTarget.getBoundingClientRect()
    const svgX = ((event.clientX - bounds.left) / bounds.width) * VIEWBOX_SIZE
    const svgY = ((event.clientY - bounds.top) / bounds.height) * VIEWBOX_SIZE

    if (
      svgX < left ||
      svgX > left + viewWidth ||
      svgY < top ||
      svgY > top + viewHeight
    ) {
      return
    }

    const x = (svgX - left) / scale - target.width / 2
    const y = target.height / 2 - (svgY - top) / scale
    onImpactSelect({ x, y })
  }

  const actualPoint = toSvgPoint(actualImpact)
  const estimatedPoint = estimatedImpact ? toSvgPoint(estimatedImpact) : null

  return (
    <div className="target-card">
      <div className="panel-heading">
        <div>
          <p className="eyebrow">Target View</p>
          <h2>{target.label}</h2>
        </div>
        <p className="panel-copy">Click anywhere on the plate to generate the true impact location.</p>
      </div>
      <svg
        className="target-svg"
        viewBox={`0 0 ${VIEWBOX_SIZE} ${VIEWBOX_SIZE}`}
        onClick={handleClick}
        role="img"
        aria-label="Interactive target surface"
      >
        <defs>
          <pattern id="target-grid" width="24" height="24" patternUnits="userSpaceOnUse">
            <path d="M 24 0 L 0 0 0 24" fill="none" stroke="rgba(108, 83, 58, 0.16)" strokeWidth="1" />
          </pattern>
        </defs>
        <rect x="0" y="0" width={VIEWBOX_SIZE} height={VIEWBOX_SIZE} rx="24" className="target-frame" />
        <rect
          x={left}
          y={top}
          width={viewWidth}
          height={viewHeight}
          rx="20"
          className="target-plate"
        />
        <rect
          x={left}
          y={top}
          width={viewWidth}
          height={viewHeight}
          rx="20"
          fill="url(#target-grid)"
          pointerEvents="none"
        />
        <line x1={left} x2={left + viewWidth} y1={VIEWBOX_SIZE / 2} y2={VIEWBOX_SIZE / 2} className="target-axis" />
        <line y1={top} y2={top + viewHeight} x1={VIEWBOX_SIZE / 2} x2={VIEWBOX_SIZE / 2} className="target-axis" />
        {sensors.filter((sensor) => sensor.enabled).map((sensor) => {
          const sensorPoint = toSvgPoint({ x: sensor.x, y: sensor.y })
          return (
            <g key={sensor.id}>
              <circle cx={sensorPoint.x} cy={sensorPoint.y} r="7" className="sensor-node" />
              <text x={sensorPoint.x + 10} y={sensorPoint.y - 10} className="sensor-label">
                {sensor.label}
              </text>
            </g>
          )
        })}
        <circle cx={actualPoint.x} cy={actualPoint.y} r="6" className="impact-actual" />
        {estimatedPoint ? (
          <>
            <circle cx={estimatedPoint.x} cy={estimatedPoint.y} r="9" className="impact-estimated-ring" />
            <circle cx={estimatedPoint.x} cy={estimatedPoint.y} r="5" className="impact-estimated" />
            <line
              x1={actualPoint.x}
              y1={actualPoint.y}
              x2={estimatedPoint.x}
              y2={estimatedPoint.y}
              className="impact-connection"
            />
          </>
        ) : null}
      </svg>
      <div className="legend-row">
        <span><i className="legend-swatch actual"></i> True impact</span>
        <span><i className="legend-swatch estimated"></i> Estimated impact</span>
        <span><i className="legend-swatch sensor"></i> Active sensor</span>
      </div>
    </div>
  )
}
"}

{"filePath":"/Users/pisan/bitbucket/pisanuw/bullet/src/lib/validation.ts","content":"import type { SensorConfig, TargetConfig } from '../types/simulation'

export function validateLayout(
  target: TargetConfig,
  sensors: SensorConfig[],
): string[] {
  const issues: string[] = []
  const activeSensors = sensors.filter((sensor) => sensor.enabled)

  if (activeSensors.length < 3) {
    issues.push('Activate at least three sensors before solving.')
  }

  if (activeSensors.length > 4) {
    issues.push('The current solver supports up to four active sensors.')
  }

  for (const sensor of activeSensors) {
    if (sensor.depth <= 0) {
      issues.push(`${sensor.label} must sit behind the target with a positive depth.`)
    }

    if (Math.abs(sensor.x) > target.width || Math.abs(sensor.y) > target.height) {
      issues.push(`${sensor.label} is positioned far outside the target footprint.`)
    }
  }

  for (let index = 0; index < activeSensors.length; index += 1) {
    const left = activeSensors[index]
    for (let compareIndex = index + 1; compareIndex < activeSensors.length; compareIndex += 1) {
      const right = activeSensors[compareIndex]
      const sameProjectedPoint = left.x === right.x && left.y === right.y
      const sameDepth = left.depth === right.depth
      if (sameProjectedPoint && sameDepth) {
        issues.push(`${left.label} and ${right.label} overlap.`)
      }
    }
  }

  if (activeSensors.length >= 3) {
    const [first, second, third] = activeSensors
    const twiceArea = Math.abs(
      first.x * (second.y - third.y) +
        second.x * (third.y - first.y) +
        third.x * (first.y - second.y),
    )

    if (twiceArea < 1) {
      issues.push('The first three active sensors are nearly colinear on the target plane.')
    }
  }

  return [...new Set(issues)]
}
"}

