export type Coordinate = {
  x: number
  y: number
}

export type TargetConfig = {
  width: number
  height: number
  label: string
  units: string
}

export type SensorConfig = {
  id: string
  label: string
  x: number
  y: number
  depth: number
  biasMicros: number
  enabled: boolean
}

export type NoiseProfile = {
  enabled: boolean
  timingJitterMicros: number
  clockDriftMicros: number
  speedVariationPercent: number
  temperatureCelsius: number
}

export type SensorMeasurement = {
  sensorId: string
  label: string
  distance: number
  idealTimeSeconds: number
  noisyTimeSeconds: number
  deltaMicros: number
}

export type TraceEntry = {
  label: string
  value: string
}

export type SolverOverlayCurve = {
  id: string
  label: string
  colorToken: string
  branches: Coordinate[][]
}

export type SolverOverlayHeatCell = {
  x: number
  y: number
  width: number
  height: number
  residualMicros: number
  normalized: number
}

export type SolverOverlayBundle = {
  hyperbolaCurves: SolverOverlayCurve[]
  residualHeatmap: SolverOverlayHeatCell[]
}

export type SolverConfidence = 'high' | 'medium' | 'low'

export type SolverResult = {
  estimatedImpact: Coordinate | null
  converged: boolean
  iterations: number
  residualMicros: number
  confidence: SolverConfidence
  trace: TraceEntry[]
}

export type SimulationState = {
  target: TargetConfig
  sensors: SensorConfig[]
  noise: NoiseProfile
  impact: Coordinate
}

export type OverlayVisibility = {
  showHyperbolas: boolean
  showResidualHeatmap: boolean
}

export type Preset = {
  id: string
  name: string
  description: string
  state: SimulationState
}

import { startTransition, useEffect, useState } from 'react'
import './App.css'
import { ConfigPanel } from './components/ConfigPanel'
import { DiagnosticsPanel } from './components/DiagnosticsPanel'
import { SensorPanel } from './components/SensorPanel'
import { TargetCanvas } from './components/TargetCanvas'
import { generateIdealMeasurements, getMissDistance, getSpeedOfSound } from './lib/geometry'
import { applyNoiseProfile } from './lib/noise'
import { buildSolverOverlayBundle } from './lib/overlay'
import { PRESETS, createDefaultState } from './lib/presets'
import { solveMultilateration } from './lib/solver/multilateration'
import { solveTdoa } from './lib/solver/tdoa'
import { loadStoredState, saveStoredState } from './lib/storage'
import { validateLayout } from './lib/validation'
import type {
  Coordinate,
  NoiseProfile,
  OverlayVisibility,
  SensorConfig,
  SimulationState,
  TargetConfig,
} from './types/simulation'

function App() {
  const [state, setState] = useState<SimulationState>(
    () => loadStoredState() ?? createDefaultState(),
  )

  useEffect(() => {
    saveStoredState(state)
  }, [state])

  const [overlayVisibility, setOverlayVisibility] = useState<OverlayVisibility>({
    showHyperbolas: true,
    showResidualHeatmap: true,
  })

  const activeSensors = state.sensors.filter((sensor) => sensor.enabled)
  const validationIssues = validateLayout(state.target, state.sensors)
  const speedOfSound = getSpeedOfSound(state.noise.temperatureCelsius)
  const idealMeasurements = generateIdealMeasurements(
    state.impact,
    state.sensors,
    state.noise.temperatureCelsius,
  )
  const measurements = applyNoiseProfile(
    idealMeasurements,
    state.sensors,
    state.noise,
  )
  const solver =
    validationIssues.length === 0
      ? activeSensors.length > 3
        ? solveMultilateration({
            target: state.target,
            sensors: activeSensors,
            measurements,
            speedOfSound,
          })
        : solveTdoa({
            target: state.target,
            sensors: activeSensors,
            measurements,
            speedOfSound,
          })
      : {
          estimatedImpact: null,
          converged: false,
          iterations: 0,
          residualMicros: Number.NaN,
          confidence: 'low' as const,
          trace: validationIssues.map((issue) => ({
            label: 'Validation',
            value: issue,
          })),
        }
  const missDistance = getMissDistance(state.impact, solver.estimatedImpact)
  const overlays = buildSolverOverlayBundle({
    target: state.target,
    sensors: activeSensors,
    measurements,
    estimatedImpact: solver.estimatedImpact,
    speedOfSound,
  })

  function updateTarget(field: keyof Pick<TargetConfig, 'width' | 'height'>, value: number) {
    startTransition(() => {
      setState((current) => {
        const target = {
          ...current.target,
          [field]: clampNumber(value, 30, 300),
        }

        return {
          ...current,
          target,
          impact: clampCoordinate(current.impact, target),
        }
      })
    })
  }

  function updateSensor(
    sensorId: string,
    field: keyof SensorConfig,
    value: number | boolean,
  ) {
    startTransition(() => {
      setState((current) => ({
        ...current,
        sensors: current.sensors.map((sensor) =>
          sensor.id === sensorId ? { ...sensor, [field]: value } : sensor,
        ),
      }))
    })
  }

  function updateNoise(field: keyof NoiseProfile, value: number | boolean) {
    startTransition(() => {
      setState((current) => ({
        ...current,
        noise: {
          ...current.noise,
          [field]: value,
        },
      }))
    })
  }

  function updateImpact(impact: Coordinate) {
    startTransition(() => {
      setState((current) => ({
        ...current,
        impact: clampCoordinate(impact, current.target),
      }))
    })
  }

  function applyPreset(presetId: string) {
    const preset = PRESETS.find((candidate) => candidate.id === presetId)
    if (!preset) {
      return
    }

    startTransition(() => {
      setState(JSON.parse(JSON.stringify(preset.state)) as SimulationState)
    })
  }

  function resetState() {
    startTransition(() => {
      setState(createDefaultState())
    })
  }

  function updateOverlayVisibility(field: keyof OverlayVisibility, value: boolean) {
    setOverlayVisibility((current) => ({
      ...current,
      [field]: value,
    }))
  }

  return (
    <main className="app-shell">
      <section className="hero-panel card">
        <div>
          <p className="eyebrow">Acoustic Impact Simulator</p>
          <h1>Simulate exactly where the bullet struck the target.</h1>
        </div>
        <p className="hero-copy">
          This prototype models a rectangular target, acoustic sensors mounted behind it,
          noisy arrival timing, and a TDOA solver that reconstructs the impact point.
        </p>
        <div className="hero-stats">
          <div>
            <span>Layout</span>
            <strong>{activeSensors.length} active sensors</strong>
          </div>
          <div>
            <span>Model</span>
            <strong>2D plane + depth</strong>
          </div>
          <div>
            <span>Physics</span>
            <strong>{state.noise.enabled ? 'Noisy timing enabled' : 'Ideal timing only'}</strong>
          </div>
        </div>
      </section>

      <section className="workspace-grid">
        <div className="workspace-main">
          <TargetCanvas
            target={state.target}
            sensors={state.sensors}
            actualImpact={state.impact}
            estimatedImpact={solver.estimatedImpact}
            overlays={overlays}
            overlayVisibility={overlayVisibility}
            onImpactSelect={updateImpact}
            onOverlayVisibilityChange={updateOverlayVisibility}
          />
          <SensorPanel measurements={measurements} />
        </div>

        <div className="workspace-side">
          <DiagnosticsPanel
            actualImpact={state.impact}
            estimatedImpact={solver.estimatedImpact}
            missDistance={missDistance}
            speedOfSound={speedOfSound}
            activeSensorCount={activeSensors.length}
            solver={solver}
            units={state.target.units}
          />
          <ConfigPanel
            target={state.target}
            sensors={state.sensors}
            noise={state.noise}
            presets={PRESETS.map((preset) => ({ id: preset.id, name: preset.name }))}
            validationIssues={validationIssues}
            onTargetChange={updateTarget}
            onSensorChange={updateSensor}
            onNoiseChange={updateNoise}
            onPresetSelect={applyPreset}
            onReset={resetState}
          />
        </div>
      </section>
    </main>
  )
}

function clampCoordinate(impact: Coordinate, target: TargetConfig): Coordinate {
  return {
    x: clampNumber(impact.x, -target.width / 2, target.width / 2),
    y: clampNumber(impact.y, -target.height / 2, target.height / 2),
  }
}

function clampNumber(value: number, minimum: number, maximum: number): number {
  return Math.min(Math.max(value, minimum), maximum)
}

export default App

import type { MouseEvent } from 'react'
import type {
  Coordinate,
  OverlayVisibility,
  SensorConfig,
  SolverOverlayBundle,
  TargetConfig,
} from '../types/simulation'

type TargetCanvasProps = {
  target: TargetConfig
  sensors: SensorConfig[]
  actualImpact: Coordinate
  estimatedImpact: Coordinate | null
  overlays: SolverOverlayBundle
  overlayVisibility: OverlayVisibility
  onImpactSelect: (impact: Coordinate) => void
  onOverlayVisibilityChange: (
    field: keyof OverlayVisibility,
    value: boolean,
  ) => void
}

const VIEWBOX_SIZE = 240
const MARGIN = 18

export function TargetCanvas({
  target,
  sensors,
  actualImpact,
  estimatedImpact,
  overlays,
  overlayVisibility,
  onImpactSelect,
  onOverlayVisibilityChange,
}: TargetCanvasProps) {
  const scaleX = (VIEWBOX_SIZE - MARGIN * 2) / target.width
  const scaleY = (VIEWBOX_SIZE - MARGIN * 2) / target.height
  const scale = Math.min(scaleX, scaleY)
  const viewWidth = target.width * scale
  const viewHeight = target.height * scale
  const left = (VIEWBOX_SIZE - viewWidth) / 2
  const top = (VIEWBOX_SIZE - viewHeight) / 2

  function toSvgPoint(point: Coordinate) {
    return {
      x: left + (point.x + target.width / 2) * scale,
      y: top + (target.height / 2 - point.y) * scale,
    }
  }

  function handleClick(event: MouseEvent<SVGSVGElement>) {
    const bounds = event.currentTarget.getBoundingClientRect()
    const svgX = ((event.clientX - bounds.left) / bounds.width) * VIEWBOX_SIZE
    const svgY = ((event.clientY - bounds.top) / bounds.height) * VIEWBOX_SIZE

    if (
      svgX < left ||
      svgX > left + viewWidth ||
      svgY < top ||
      svgY > top + viewHeight
    ) {
      return
    }

    const x = (svgX - left) / scale - target.width / 2
    const y = target.height / 2 - (svgY - top) / scale
    onImpactSelect({ x, y })
  }

  const actualPoint = toSvgPoint(actualImpact)
  const estimatedPoint = estimatedImpact ? toSvgPoint(estimatedImpact) : null

  return (
    <div className="target-card">
      <div className="panel-heading">
        <div>
          <p className="eyebrow">Target View</p>
          <h2>{target.label}</h2>
        </div>
        <p className="panel-copy">Click anywhere on the plate to generate the true impact location.</p>
      </div>
      <div className="overlay-controls">
        <label className="toggle">
          <input
            type="checkbox"
            checked={overlayVisibility.showHyperbolas}
            onChange={(event) =>
              onOverlayVisibilityChange('showHyperbolas', event.target.checked)
            }
          />
          <span>Show TDOA hyperbolas</span>
        </label>
        <label className="toggle">
          <input
            type="checkbox"
            checked={overlayVisibility.showResidualHeatmap}
            onChange={(event) =>
              onOverlayVisibilityChange('showResidualHeatmap', event.target.checked)
            }
          />
          <span>Show residual heatmap</span>
        </label>
      </div>
      <svg
        className="target-svg"
        viewBox={`0 0 ${VIEWBOX_SIZE} ${VIEWBOX_SIZE}`}
        onClick={handleClick}
        role="img"
        aria-label="Interactive target surface"
      >
        <defs>
          <pattern id="target-grid" width="24" height="24" patternUnits="userSpaceOnUse">
            <path d="M 24 0 L 0 0 0 24" fill="none" stroke="rgba(108, 83, 58, 0.16)" strokeWidth="1" />
          </pattern>
        </defs>
        <rect x="0" y="0" width={VIEWBOX_SIZE} height={VIEWBOX_SIZE} rx="24" className="target-frame" />
        <rect
          x={left}
          y={top}
          width={viewWidth}
          height={viewHeight}
          rx="20"
          className="target-plate"
        />
        <rect
          x={left}
          y={top}
          width={viewWidth}
          height={viewHeight}
          rx="20"
          fill="url(#target-grid)"
          pointerEvents="none"
        />
        <clipPath id="target-clip">
          <rect x={left} y={top} width={viewWidth} height={viewHeight} rx="20" />
        </clipPath>
        {overlayVisibility.showResidualHeatmap ? (
          <g clipPath="url(#target-clip)" className="overlay-heatmap">
            {overlays.residualHeatmap.map((cell) => {
              const point = toSvgPoint({ x: cell.x, y: cell.y })
              const width = cell.width * scale
              const height = cell.height * scale

              return (
                <rect
                  key={`${cell.x}-${cell.y}`}
                  x={point.x - width / 2}
                  y={point.y - height / 2}
                  width={width}
                  height={height}
                  fill={`rgba(177, 69, 40, ${cell.normalized * 0.5})`}
                  className="overlay-heat-cell"
                >
                  <title>{`${cell.residualMicros.toFixed(2)} microseconds RMS residual`}</title>
                </rect>
              )
            })}
          </g>
        ) : null}
        <line x1={left} x2={left + viewWidth} y1={VIEWBOX_SIZE / 2} y2={VIEWBOX_SIZE / 2} className="target-axis" />
        <line y1={top} y2={top + viewHeight} x1={VIEWBOX_SIZE / 2} x2={VIEWBOX_SIZE / 2} className="target-axis" />
        {overlayVisibility.showHyperbolas
          ? overlays.hyperbolaCurves.map((curve) =>
              curve.branches.map((branch, branchIndex) => (
                <path
                  key={`${curve.id}-${branchIndex}`}
                  d={branch
                    .map((point, pointIndex) => {
                      const svgPoint = toSvgPoint(point)
                      return `${pointIndex === 0 ? 'M' : 'L'} ${svgPoint.x} ${svgPoint.y}`
                    })
                    .join(' ')}
                  className={`overlay-curve ${curve.colorToken}`}
                >
                  <title>{curve.label}</title>
                </path>
              )),
            )
          : null}
        {sensors.filter((sensor) => sensor.enabled).map((sensor) => {
          const sensorPoint = toSvgPoint({ x: sensor.x, y: sensor.y })
          return (
            <g key={sensor.id}>
              <circle cx={sensorPoint.x} cy={sensorPoint.y} r="7" className="sensor-node" />
              <text x={sensorPoint.x + 10} y={sensorPoint.y - 10} className="sensor-label">
                {sensor.label}
              </text>
            </g>
          )
        })}
        <circle cx={actualPoint.x} cy={actualPoint.y} r="6" className="impact-actual" />
        {estimatedPoint ? (
          <>
            <circle cx={estimatedPoint.x} cy={estimatedPoint.y} r="9" className="impact-estimated-ring" />
            <circle cx={estimatedPoint.x} cy={estimatedPoint.y} r="5" className="impact-estimated" />
            <line
              x1={actualPoint.x}
              y1={actualPoint.y}
              x2={estimatedPoint.x}
              y2={estimatedPoint.y}
              className="impact-connection"
            />
          </>
        ) : null}
      </svg>
      <div className="legend-row">
        <span><i className="legend-swatch actual"></i> True impact</span>
        <span><i className="legend-swatch estimated"></i> Estimated impact</span>
        <span><i className="legend-swatch sensor"></i> Active sensor</span>
        <span><i className="legend-swatch curve"></i> TDOA hyperbola</span>
        <span><i className="legend-swatch heat"></i> Residual field</span>
      </div>
    </div>
  )
}

